public void processMethodAndClassName(String toString) {
    Matcher matcher = METHOD_AND_CLASS_NAME_PATTERN.matcher(toString());

    // Find the first occurrence of the pattern in the string
    if (matcher.find()) {
        String matchedString = matcher.group();

        // Extract the method and class name from the matched string
        int start = matchedString.indexOf(' ');
        int end = matchedString.length() - 1;

        String methodName = matchedString.substring(0, start);
        String className = matchedString.substring(start + 1, end + 1);

        // Process the extracted method and class name
        processMethod(methodName);
        processClassName(className);
    }
