public Object executeMethod(Object targetObject) {
    // Check if the target object is an instance of a class that implements IExecutable
    if (targetObject instanceof IExecutable) {
        IExecutable executable = (IExecutable) targetObject;
        return executable.getAnnotations();
    } else {
        throw new IllegalArgumentException("Target object must implement IExecutable interface");
    }
}

