public double getRuntimeInMilliseconds() {
    // Convert the runtime to milliseconds
    long millis = runTime * 1000;

    // Format the milliseconds as a string with two decimal places
    NumberFormat numberFormat = NumberFormat.getInstance();
    numberFormat.setMaximumFractionDigits(2);
    String formattedTime = numberFormat.format(millis);

    return Double.parseDouble(formattedTime);
}

